mapper.sql:
qna_id = #{qnaId}

	and quest_st = #{param.questStatus}


	and category_cd = #{param.categoryCd}


	and title like ('%' || #{param.title} || '%')


	and questioner_id in (select member_id from cmmt_member where member_nm = #{param.memberNm})


	and quest_created_dt between to_timestamp(#{param.questBeginDay} || '000000', 'yyyymmddhh24miss') and to_timestamp(#{param.questEndDay} || '235959', 'yyyymmddhh24miss')


	and questioner_id = #{questionerId}

mapper.update:
/** CmmtQnaQuestDao.update */
update cmmt_qna_quest set
	 qna_id                     = #{qnaId}
	,category_cd                = #{categoryCd}
	,quest_st                   = #{questSt}
	,quest_st_dt                = #{questStDt}
	,title                      = #{title}
	,question                   = #{question}
	,quest_attachment_group_id  = #{questAttachmentGroupId}
	,questioner_id              = #{questionerId}
	,quest_created_dt           = #{questCreatedDt}
	,quest_updated_dt           = #{questUpdatedDt}
	,answer                     = #{answer}
	,answer_attachment_group_id = #{answerAttachmentGroupId}
	,answer_creator_id          = #{answerCreatorId}
	,answer_created_dt          = #{answerCreatedDt}
	,answer_updater_id          = #{answerUpdaterId}
	,answer_updated_dt          = #{answerUpdatedDt}
where
	quest_id = #{questId}

mapper.insert:
/** CmmtQnaQuestDao.insert */
insert into cmmt_qna_quest (
	 quest_id
	,qna_id
	,category_cd
	,quest_st
	,quest_st_dt
	,title
	,question
	,quest_attachment_group_id
	,questioner_id
	,quest_created_dt
	,quest_updated_dt
	,answer
	,answer_attachment_group_id
	,answer_creator_id
	,answer_created_dt
	,answer_updater_id
	,answer_updated_dt
) values (
	 #{questId}
	,#{qnaId}
	,#{categoryCd}
	,#{questSt}
	,#{questStDt}
	,#{title}
	,#{question}
	,#{questAttachmentGroupId}
	,#{questionerId}
	,#{questCreatedDt}
	,#{questUpdatedDt}
	,#{answer}
	,#{answerAttachmentGroupId}
	,#{answerCreatorId}
	,#{answerCreatedDt}
	,#{answerUpdaterId}
	,#{answerUpdatedDt}
)

mapper.delete:
/** CmmtQnaQuestDao.delete */
delete from
	cmmt_qna_quest
where
	quest_id = #{questId}
